rder-radius: 30px;\n    font-weight: 700;\n    font-size: 15px;\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    text-decoration: none;\n    transition: background-color 0.2s ease;\n    border: none;\n}\n\n.header-style-3 .header-btn-area a:hover {\n    background-color: #e02c30 !important;\n}\n\n/* ===== BANNER SEARCH HERO BAR STYLING ===== */\n.banner-search-h2 {\n    background: #ffffff;\n    border-radius: 12px;\n    padding: 8px !important;\n    box-shadow: 0 10px 30px rgba(0,0,0,0.15);\n    max-width: 950px;\n    margin: 0 auto;\n}\n\n.banner-search-h2 .rtcl-search-input-button-wrap {\n    display: flex;\n    align-items: center;\n    width: 100%;\n}\n\n.banner-search-h2 .rtcl-search-input-wrap {\n    flex: 1;\n    display: flex;\n    align-items: center;\n    border-right: 1px solid #eef0f6;\n    padding: 0 15px;\n}\n\n.banner-search-h2 select,\n.banner-search-h2 input {\n    border: none !important;\n    outline: none !important;\n    font-size: 15px;\n    color: #515167;\n    width: 100%;\n    background: transparent;\n    height: 48px;\n}\n\n.banner-search-h2 .rtcl-search-btn-wrap {\n    padding-left: 10px;\n}\n\n.banner-search-h2 button.rtcl-search-btn {\n    background-color: #02c5bd !important;\n    color: #ffffff !important;\n    border-radius: 8px;\n    height: 48px;\n    padding: 0 30px;\n    font-weight: 700;\n    font-size: 16px;\n    border: none;\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    cursor: pointer;\n    transition: background-color 0.2s ease;\n}\n\n.banner-search-h2 button.rtcl-search-btn:hover {\n    background-color: #02afaa !important;\n}\n\n/* Fix category circles hover and styling to match design */\n.category-list.layout-3 .category-item .icon {\n    width: 70px;\n    height: 70px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin-bottom: 12px;\n    transition: transform 0.2s ease, box-shadow 0.2s ease;\n}\n\n.category-list.layout-3 .category-item:hover .icon {\n    transform: translateY(-5px);\n    box-shadow: 0 8px 20px rgba(0,0,0,0.15);\n}\n\n.category-list.layout-3 .category-item .category-name {\n    color: #ffffff !important;\n    font-weight: 700;\n    font-size: 16px;\n    text-decoration: none;\n}\n\n.category-list.layout-3 .category-item .item-number {\n    color: rgba(255,255,255,0.7) !important;\n    font-size: 14px;\n    margin: 4px 0 0 0;\n}\n','petslist','','inherit','closed','closed','','4655-revision-v1','','','2026-06-28 05:15:39','2026-06-28 05:15:39','',4655,'https://computerkingdom.co/dog/?p=4657',0,'revision','',0),
