-list.layout-3 .category-item:hover .icon {\n    transform: translateY(-5px);\n    box-shadow: 0 8px 20px rgba(0,0,0,0.15);\n}\n\n.category-list.layout-3 .category-item .category-name {\n    color: #ffffff !important;\n    font-weight: 700;\n    font-size: 16px;\n    text-decoration: none;\n}\n\n.category-list.layout-3 .category-item .item-number {\n    color: rgba(255,255,255,0.7) !important;\n    font-size: 14px;\n    margin: 4px 0 0 0;\n}\n\n\n/* ===== PRICING TABLE CHECKMARK ICON FIXES ===== */\n.rt-pricing-features .rt-pricing-features-list li svg,\n.rt-pricing-features .rt-pricing-features-list li i,\n.rt-pricing-features .rt-pricing-features-list li .elementor-icon {\n    width: 20px !important;\n    height: 20px !important;\n    min-width: 20px !important;\n    min-height: 20px !important;\n    max-width: 20px !important;\n    max-height: 20px !important;\n    font-size: 20px !important;\n    line-height: 20px !important;\n    display: inline-block !important;\n    vertical-align: middle !important;\n    color: #02c5bd !important;\n    fill: #02c5bd !important;\n    margin-right: 10px !important;\n}\n\n.rt-pricing-features .rt-pricing-features-list li {\n    display: flex !important;\n    align-items: center !important;\n    font-size: 16px !important;\n    line-height: 24px !important;\n    margin-bottom: 12px !important;\n    text-transform: capitalize !important;\n    color: #515167 !important;\n}\n\n.rt-pricing-features .rt-pricing-features-list li span {\n    display: inline-block !important;\n    vertical-align: middle !important;\n}\n\n\n/* ===== APP BUTTON SVG ICON FIXES ===== */\n.button-arapper a.app-btn svg,\n.button-arapper a.app-btn i {\n    width: 40px !important;\n    height: 40px !important;\n    min-width: 40px !important;\n    min-height: 40px !important;\n    max-width: 40px !important;\n    max-height: 40px !important;\n    font-size: 40px !important;\n    color: #ffffff !important;\n    fill: #ffffff !important;\n    display: inline-block !important;\n    vertical-align: middle !important;\n}\n\n.button-arapper a.app-btn {\n    align-items: center !important;\n    display: inline-flex !important;\n    gap: 15px !important;\n}\n\n\n/* ===== FOOTER STYLE 3 LOGO RED BACKGROUND ===== */\n.footer-style-3 .copyright-logo {\n    background-color: #ff3d41 !important;\n    padding: 20px 35px !important;\n    display: inline-flex !important;\n    align-items: center !important;\n    justify-content: center !important;\n    margin-right: 20px;\n    height: 75px;\n    box-sizing: border-box;\n}\n\n.footer-style-3 .copyright-logo img,\n.footer-style-3 .copyright-logo svg {\n    max-height: 35px !important;\n    width: auto !important;\n    display: block !important;\n}\n\n.footer-style-3 .copyright-area {\n    display: flex !important;\n    align-items: center !important;\n    justify-content: space-between !important;\n}\n\n.footer-style-3 .copyright-text {\n    flex-grow: 1;\n    margin-left: 20px;\n}\n','petslist','','inherit','closed','closed','','4655-revision-v1','','','2026-06-28 05:34:56','2026-06-28 05:34:56','',4655,'https://computerkingdom.co/dog/?p=4670',0,'revision','',0),
