rder-radius: 30px;\n    font-weight: 700;\n    font-size: 15px;\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    text-decoration: none;\n    transition: background-color 0.2s ease;\n    border: none;\n}\n\n.header-style-3 .header-btn-area a:hover {\n    background-color: #e02c30 !important;\n}\n\n/* ===== BANNER SEARCH HERO BAR STYLING ===== */\n.banner-search-h2 {\n    background: #ffffff;\n    border-radius: 12px;\n    padding: 8px !important;\n    box-shadow: 0 10px 30px rgba(0,0,0,0.15);\n    max-width: 950px;\n    margin: 0 auto;\n}\n\n.banner-search-h2 .rtcl-search-input-button-wrap {\n    display: flex;\n    align-items: center;\n    width: 100%;\n}\n\n.banner-search-h2 .rtcl-search-input-wrap {\n    flex: 1;\n    display: flex;\n    align-items: center;\n    border-right: 1px solid #eef0f6;\n    padding: 0 15px;\n}\n\n.banner-search-h2 select,\n.banner-search-h2 input {\n    border: none !important;\n    outline: none !important;\n    font-size: 15px;\n    color: #515167;\n    width: 100%;\n    background: transparent;\n    height: 48px;\n}\n\n.banner-search-h2 .rtcl-search-btn-wrap {\n    padding-left: 10px;\n}\n\n.banner-search-h2 button.rtcl-search-btn {\n    background-color: #02c5bd !important;\n    color: #ffffff !important;\n    border-radius: 8px;\n    height: 48px;\n    padding: 0 30px;\n    font-weight: 700;\n    font-size: 16px;\n    border: none;\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    cursor: pointer;\n    transition: background-color 0.2s ease;\n}\n\n.banner-search-h2 button.rtcl-search-btn:hover {\n    background-color: #02afaa !important;\n}\n\n/* Fix category circles hover and styling to match design */\n.category-list.layout-3 .category-item .icon {\n    width: 70px;\n    height: 70px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin-bottom: 12px;\n    transition: transform 0.2s ease, box-shadow 0.2s ease;\n}\n\n.category-list.layout-3 .category-item:hover .icon {\n    transform: translateY(-5px);\n    box-shadow: 0 8px 20px rgba(0,0,0,0.15);\n}\n\n.category-list.layout-3 .category-item .category-name {\n    color: #ffffff !important;\n    font-weight: 700;\n    font-size: 16px;\n    text-decoration: none;\n}\n\n.category-list.layout-3 .category-item .item-number {\n    color: rgba(255,255,255,0.7) !important;\n    font-size: 14px;\n    margin: 4px 0 0 0;\n}\n\n\n/* ===== PRICING TABLE CHECKMARK ICON FIXES ===== */\n.rt-pricing-features .rt-pricing-features-list li svg,\n.rt-pricing-features .rt-pricing-features-list li i,\n.rt-pricing-features .rt-pricing-features-list li .elementor-icon {\n    width: 20px !important;\n    height: 20px !important;\n    min-width: 20px !important;\n    min-height: 20px !important;\n    max-width: 20px !important;\n    max-height: 20px !important;\n    font-size: 20px !important;\n    line-height: 20px !important;\n    display: inline-block !important;\n    vertical-align: middle !important;\n    color: #02c5bd !important;\n    fill: #02c5bd !important;\n    margin-right: 10px !important;\n}\n\n.rt-pricing-features .rt-pricing-features-list li {\n    display: flex !important;\n    align-items: center !important;\n    font-size: 16px !important;\n    line-height: 24px !important;\n    margin-bottom: 12px !important;\n    text-transform: capitalize !important;\n    color: #515167 !important;\n}\n\n.rt-pricing-features .rt-pricing-features-list li span {\n    display: inline-block !important;\n    vertical-align: middle !important;\n}\n\n\n/* ===== APP BUTTON SVG ICON FIXES ===== */\n.button-arapper a.app-btn svg,\n.button-arapper a.app-btn i {\n    width: 40px !important;\n    height: 40px !important;\n    min-width: 40px !important;\n    min-height: 40px !important;\n    max-width: 40px !important;\n    max-height: 40px !important;\n    font-size: 40px !important;\n    color: #ffffff !important;\n    fill: #ffffff !important;\n    display: inline-block !important;\n    vertical-align: middle !important;\n}\n\n.button-arapper a.app-btn {\n    align-items: center !important;\n    display: inline-flex !important;\n    gap: 15px !important;\n}\n\n\n/* ===== FOOTER STYLE 3 LOGO RED BACKGROUND ===== */\n.footer-style-3 .copyright-logo {\n    background-color: #ff3d41 !important;\n    padding: 20px 35px !important;\n    display: inline-flex !important;\n    align-items: center !important;\n    justify-content: center !important;\n    margin-right: 20px;\n    height: 75px;\n    box-sizing: border-box;\n}\n\n.footer-style-3 .copyright-logo img,\n.footer-style-3 .copyright-logo svg {\n    max-height: 35px !important;\n    width: auto !important;\n    display: block !important;\n}\n\n.footer-style-3 .copyright-area {\n    display: flex !important;\n    align-items: center !important;\n    justify-content: space-between !important;\n}\n\n.footer-style-3 .copyright-text {\n    flex-grow: 1;\n    margin-left: 20px;\n}\n\n\n/* ===== PREMIUM LOGIN &amp; REGISTRATION CARD LAYOUT ===== */\n#rtcl-user-login-wrapper {\n    display: flex !important;\n    flex-wrap: wrap !important;\n    gap: 40px !important;\n    justify-content: center !important;\n    margin: 50px auto !important;\n    max-width: 1100px !important;\n    padding: 0 15px !important;\n}\n\n#rtcl-user-login-wrapper.have-registration-form .rtcl-login-form-wrap,\n#rtcl-user-login-wrapper.have-registration-form .rtcl-registration-form-wrap {\n    flex: 1 1 450px !important;\n    background: #ffffff !important;\n    border: 1px solid #eef1f6 !important;\n    border-radius: 16px !important;\n    padding: 40px !important;\n    box-shadow: 0 10px 30px rgba(7, 12, 62, 0.05) !important;\n    transition: transform 0.3s ease, box-shadow 0.3s ease !important;\n}\n\n#rtcl-user-login-wrapper.have-registration-form .rtcl-login-form-wrap:hover,\n#rtcl-user-login-wrapper.have-registration-form .rtcl-registration-form-wrap:hover {\n    transform: translateY(-5px) !important;\n    box-shadow: 0 15px 35px rgba(7, 12, 62, 0.08) !important;\n}\n\n#rtcl-user-login-wrapper h2 {\n    font-family: var(--petslist-heading-font) !important;\n    color: #070c3e !important;\n    font-size: 28px !important;\n    font-weight: 700 !important;\n    margin-top: 0 !important;\n    margin-bottom: 30px !important;\n    padding-bottom: 12px !important;\n    border-bottom: 2px solid #eef1f6 !important;\n    position: relative !important;\n}\n\n#rtcl-user-login-wrapper h2::after {\n    content: \"\" !important;\n    position: absolute !important;\n    bottom: -2px !important;\n    left: 0 !important;\n    width: 60px !important;\n    height: 2px !important;\n    background-color: #02c5bd !important;\n}\n\n/* Form Groups &amp; Inputs */\n#rtcl-user-login-wrapper .rtcl-form-group,\n#rtcl-user-login-wrapper .form-group {\n    margin-bottom: 20px !important;\n}\n\n#rtcl-user-login-wrapper label.rtcl-field-label,\n#rtcl-user-login-wrapper label {\n    font-family: var(--petslist-body-font) !important;\n    font-weight: 600 !important;\n    color: #070c3e !important;\n    font-size: 15px !important;\n    margin-bottom: 8px !important;\n    display: block !important;\n}\n\n#rtcl-user-login-wrapper label .rtcl-required {\n    color: #ff3d41 !important;\n}\n\n#rtcl-user-login-wrapper .rtcl-form-control,\n#rtcl-user-login-wrapper input[type=\"text\"],\n#rtcl-user-login-wrapper input[type=\"email\"],\n#rtcl-user-login-wrapper input[type=\"password\"] {\n    background: #f8fafc !important;\n    border: 1px solid #e2e8f0 !important;\n    border-radius: 10px !important;\n    height: 52px !important;\n    padding: 10px 18px !important;\n    font-size: 15px !important;\n    color: #070c3e !important;\n    width: 100% !important;\n    transition: all 0.2s ease !important;\n    outline: none !important;\n    box-sizing: border-box !important;\n}\n\n#rtcl-user-login-wrapper .rtcl-form-control:focus,\n#rtcl-user-login-wrapper input[type=\"text\"]:focus,\n#rtcl-user-login-wrapper input[type=\"email\"]:focus,\n#rtcl-user-login-wrapper input[type=\"password\"]:focus {\n    border-color: #02c5bd !important;\n    background: #ffffff !important;\n    box-shadow: 0 0 0 4px rgba(2, 197, 189, 0.12) !important;\n}\n\n/* Passwords Toggle Eye Icon */\n#rtcl-user-login-wrapper .rtcl-user-pass-wrap {\n    position: relative !important;\n}\n\n#rtcl-user-login-wrapper .rtcl-toggle-pass {\n    position: absolute !important;\n    right: 18px !important;\n    top: 50% !important;\n    transform: translateY(-50%) !important;\n    cursor: pointer !important;\n    color: #64748b !important;\n    font-size: 18px !important;\n}\n\n/* Submit Buttons */\n#rtcl-user-login-wrapper input[type=\"submit\"],\n#rtcl-user-login-wrapper button.rtcl-btn {\n    background-color: #02c5bd !important;\n    border: none !important;\n    color: #ffffff !important;\n    height: 52px !important;\n    padding: 0 35px !important;\n    border-radius: 30px !important;\n    font-weight: 700 !important;\n    font-size: 16px !important;\n    cursor: pointer !important;\n    transition: all 0.2s ease !important;\n    display: inline-flex !important;\n    align-items: center !important;\n    justify-content: center !important;\n    box-shadow: 0 4px 12px rgba(2, 197, 189, 0.2) !important;\n}\n\n#rtcl-user-login-wrapper input[type=\"submit\"]:hover,\n#rtcl-user-login-wrapper button.rtcl-btn:hover {\n    background-color: #02afaa !important;\n    box-shadow: 0 6px 18px rgba(2, 197, 189, 0.3) !important;\n    transform: translateY(-1px) !important;\n}\n\n/* Checkbox &amp; Remember Me */\n#rtcl-user-login-wrapper .form-check-label {\n    display: inline-flex !important;\n    align-items: center !important;\n    gap: 8px !important;\n    font-weight: 500 !important;\n    color: #515167 !important;\n    cursor: pointer !important;\n}\n\n/* Links &amp; Help text */\n#rtcl-user-login-wrapper a {\n    color: #02c5bd !important;\n    font-weight: 600 !important;\n    text-decoration: none !important;\n    transition: color 0.2s ease !important;\n}\n\n#rtcl-user-login-wrapper a:hover {\n    color: #02afaa !important;\n}\n\n#rtcl-user-login-wrapper span.help-block {\n    font-size: 13px !important;\n    color: #64748b !important;\n    margin-top: 6px !important;\n    display: block !important;\n}\n\n/* Responsive adjustments */\n@media (max-width: 991px) {\n    #rtcl-user-login-wrapper {\n        flex-direction: column !important;\n    }\n    #rtcl-user-login-wrapper.have-registration-form .rtcl-login-form-wrap,\n    #rtcl-user-login-wrapper.have-registration-form .rtcl-registration-form-wrap {\n        flex: 1 1 100% !important;\n        padding: 30px !important;\n    }\n}\n\n\n/* ===== TABBED AUTH SWITCHER DESIGN ===== */\n.rtcl-tabbed-auth-wrapper {\n    max-width: 580px !important;\n    margin: 60px auto !important;\n    padding: 0 15px !important;\n    display: block !important;\n}\n\n/* Nav tabs wrapper */\n.rtcl-auth-tabs-nav {\n    display: flex !important;\n    background: #f8fafc !important;\n    border: 1px solid #eef1f6 !important;\n    border-bottom: none !important;\n    border-radius: 16px 16px 0 0 !important;\n    overflow: hidden !important;\n    padding: 6px !important;\n    gap: 6px !important;\n}\n\n/* Tab button styling */\n.rtcl-auth-tab-btn {\n    flex: 1 !important;\n    background: transparent !important;\n    border: none !important;\n    padding: 14px 20px !important;\n    font-size: 16px !important;\n    font-weight: 700 !important;\n    font-family: var(--petslist-heading-font) !important;\n    color: #64748b !important;\n    cursor: pointer !important;\n    border-radius: 12px !important;\n    transition: all 0.25s ease !important;\n    display: inline-flex !important;\n    align-items: center !important;\n    justify-content: center !important;\n    gap: 8px !important;\n    outline: none !important;\n}\n\n.rtcl-auth-tab-btn i {\n    font-size: 16px !important;\n    color: #64748b !important;\n    transition: color 0.25s ease !important;\n}\n\n/* Active tab button */\n.rtcl-auth-tab-btn.active {\n    background: #ffffff !important;\n    color: #02c5bd !important;\n    box-shadow: 0 4px 12px rgba(7, 12, 62, 0.04) !important;\n}\n\n.rtcl-auth-tab-btn.active i {\n    color: #02c5bd !important;\n}\n\n/* Tab Panels container card */\n.rtcl-auth-tab-contents {\n    background: #ffffff !important;\n    border: 1px solid #eef1f6 !important;\n    border-top: none !important;\n    border-radius: 0 0 16px 16px !important;\n    box-shadow: 0 15px 35px rgba(7, 12, 62, 0.05) !important;\n    overflow: hidden !important;\n}\n\n.rtcl-auth-panel {\n    display: none !important;\n    padding: 40px !important;\n    animation: authFadeIn 0.3s ease !important;\n}\n\n.rtcl-auth-panel.active {\n    display: block !important;\n}\n\n#rtcl-user-login-wrapper h2 {\n    font-size: 24px !important;\n    margin-bottom: 25px !important;\n    border-bottom: none !important;\n    padding-bottom: 0 !important;\n}\n\n#rtcl-user-login-wrapper h2::after {\n    display: none !important;\n}\n\n@keyframes authFadeIn {\n    from { opacity: 0; transform: translateY(5px); }\n    to { opacity: 1; transform: translateY(0); }\n}\n\n@media (max-width: 575px) {\n    .rtcl-auth-panel {\n        padding: 25px !important;\n    }\n}\n','petslist','','inherit','closed','closed','','4655-revision-v1','','','2026-06-28 05:38:01','2026-06-28 05:38:01','',4655,'https://computerkingdom.co/dog/?p=4672',0,'revision','',0),
